import React, { Component } from 'react';
import { Document } from 'react-pdf'

class Resume extends Component {
    render() {
        return (
            <div className="content">
                <div className="resume-style">
                    <h1>Resume</h1>
                    <ReactPDF file={"../assets/resume.pdf"}/>
                </div>
            </div>
        )
    }
}

export default Resume;
